* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    background: white;
    border-radius: 12px;
    padding: 40px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    text-align: center;
}

h1 {
    color: #333;
    margin-bottom: 30px;
    font-size: 2.5em;
}

.game-info {
    margin-bottom: 30px;
    font-size: 1.1em;
}

.status {
    display: flex;
    flex-direction: column;
    gap: 10px;
    color: #555;
}

.status span {
    min-height: 24px;
}

.status strong {
    color: #667eea;
    font-weight: 600;
}

.status span.hidden {
    display: none;
}

#winner strong {
    color: #22c55e;
    font-size: 1.2em;
}

#draw {
    color: #f59e0b;
    font-weight: 600;
}

.board {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 8px;
    margin: 30px auto;
    width: 300px;
}

.cell {
    width: 100px;
    height: 100px;
    font-size: 2.5em;
    font-weight: bold;
    border: 2px solid #ddd;
    border-radius: 8px;
    background: white;
    cursor: pointer;
    transition: all 0.2s ease;
    color: #333;
}

.cell:hover:not(:disabled) {
    background: #f5f5f5;
    border-color: #667eea;
    transform: scale(1.05);
}

.cell:active:not(:disabled) {
    transform: scale(0.98);
}

.cell:disabled {
    cursor: not-allowed;
}

.cell.x {
    color: #3b82f6;
}

.cell.o {
    color: #ef4444;
}

.cell.winning {
    background: #fbbf24;
    border-color: #f59e0b;
    font-weight: 900;
    box-shadow: 0 0 10px rgba(245, 158, 11, 0.5);
}

.reset-btn {
    padding: 12px 40px;
    font-size: 1.1em;
    font-weight: 600;
    color: white;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    border: none;
    border-radius: 8px;
    cursor: pointer;
    transition: all 0.3s ease;
    margin-top: 20px;
}

.reset-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 10px 20px rgba(102, 126, 234, 0.4);
}

.reset-btn:active {
    transform: translateY(0);
}

