// 간단한 assert 함수
function assert(condition, message) {
    if (!condition) {
        console.error(`❌ FAIL: ${message}`);
        process.exitCode = 1;
    } else {
        console.log(`✓ PASS: ${message}`);
    }
}

// TicTacToe 클래스 import (Node.js 환경)
class TicTacToe {
    constructor() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;
        this.winningCells = [];
    }

    handleCellClick(index) {
        if (this.board[index] !== null || this.gameOver) {
            return;
        }

        this.board[index] = this.currentPlayer;

        if (this.checkWin()) {
            this.gameOver = true;
            this.winner = this.currentPlayer;
            return;
        }

        if (this.checkDraw()) {
            this.gameOver = true;
            return;
        }

        this.currentPlayer = this.currentPlayer === 'X' ? 'O' : 'X';
    }

    checkWin() {
        const winPatterns = [
            [0, 1, 2],
            [3, 4, 5],
            [6, 7, 8],
            [0, 3, 6],
            [1, 4, 7],
            [2, 5, 8],
            [0, 4, 8],
            [2, 4, 6]
        ];

        return winPatterns.some(pattern => {
            const [a, b, c] = pattern;
            if (
                this.board[a] === this.currentPlayer &&
                this.board[b] === this.currentPlayer &&
                this.board[c] === this.currentPlayer
            ) {
                this.winningCells = pattern;
                return true;
            }
            return false;
        });
    }

    checkDraw() {
        return this.board.every(cell => cell !== null);
    }

    reset() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;
        this.winningCells = [];
    }
}

// ==================== 테스트 시작 ====================
console.log('\n🎮 틱택토 게임 테스트 시작\n');

// 테스트 1: 첫 번째 행 승리 감지
console.log('테스트 1: 첫 번째 행 승리 감지');
{
    const game = new TicTacToe();
    game.handleCellClick(0); // X
    game.handleCellClick(3); // O
    game.handleCellClick(1); // X
    game.handleCellClick(4); // O
    game.handleCellClick(2); // X - 승리!

    assert(game.winner === 'X', '승자가 X여야 함');
    assert(game.gameOver === true, '게임이 끝나야 함');
    assert(game.winningCells.join(',') === '0,1,2', '우승 셀이 [0,1,2]여야 함');
}

// 테스트 2: 세 번째 행 승리 감지
console.log('\n테스트 2: 세 번째 행 승리 감지');
{
    const game = new TicTacToe();
    game.handleCellClick(0); // X
    game.handleCellClick(6); // O
    game.handleCellClick(1); // X
    game.handleCellClick(7); // O
    game.handleCellClick(4); // X
    game.handleCellClick(8); // O - 승리!

    assert(game.winner === 'O', '승자가 O여야 함');
    assert(game.gameOver === true, '게임이 끝나야 함');
    assert(game.winningCells.join(',') === '6,7,8', '우승 셀이 [6,7,8]여야 함');
}

// 테스트 3: 첫 번째 열 승리 감지
console.log('\n테스트 3: 첫 번째 열 승리 감지');
{
    const game = new TicTacToe();
    game.handleCellClick(0); // X
    game.handleCellClick(1); // O
    game.handleCellClick(3); // X
    game.handleCellClick(2); // O
    game.handleCellClick(6); // X - 승리!

    assert(game.winner === 'X', '승자가 X여야 함');
    assert(game.winningCells.join(',') === '0,3,6', '우승 셀이 [0,3,6]여야 함');
}

// 테스트 4: 대각선(0-4-8) 승리 감지
console.log('\n테스트 4: 대각선(0-4-8) 승리 감지');
{
    const game = new TicTacToe();
    game.handleCellClick(0); // X
    game.handleCellClick(1); // O
    game.handleCellClick(4); // X
    game.handleCellClick(2); // O
    game.handleCellClick(8); // X - 승리!

    assert(game.winner === 'X', '승자가 X여야 함');
    assert(game.winningCells.join(',') === '0,4,8', '우승 셀이 [0,4,8]여야 함');
}

// 테스트 5: 대각선(2-4-6) 승리 감지
console.log('\n테스트 5: 대각선(2-4-6) 승리 감지');
{
    const game = new TicTacToe();
    game.handleCellClick(2); // X
    game.handleCellClick(0); // O
    game.handleCellClick(4); // X
    game.handleCellClick(1); // O
    game.handleCellClick(6); // X - 승리!

    assert(game.winner === 'X', '승자가 X여야 함');
    assert(game.winningCells.join(',') === '2,4,6', '우승 셀이 [2,4,6]여야 함');
}

// 테스트 6: 무승부 감지
console.log('\n테스트 6: 무승부 감지');
{
    const game = new TicTacToe();
    // 무승부 배치 (승자가 없는 상태)
    // X O X
    // O X O
    // O X X
    game.board = ['X', 'O', 'X', 'O', 'X', 'O', 'O', 'X', 'X'];

    // 게임 상태 확인 (수동으로 설정)
    game.currentPlayer = 'X'; // 마지막은 X가 놓음
    game.gameOver = game.checkDraw();

    if (!game.gameOver) {
        game.winner = null; // 승자 없음
    }

    assert(game.gameOver === true, '게임이 끝나야 함');
    assert(game.winner === null, '승자가 없어야 함 (무승부)');
    assert(game.board.every(cell => cell !== null), '모든 셀이 차있어야 함');
}

// 테스트 7: 턴 전환
console.log('\n테스트 7: 턴 전환');
{
    const game = new TicTacToe();
    assert(game.currentPlayer === 'X', '초기 플레이어는 X');

    game.handleCellClick(0);
    assert(game.currentPlayer === 'O', '첫 이동 후 O 차례');

    game.handleCellClick(1);
    assert(game.currentPlayer === 'X', '두 번째 이동 후 X 차례');

    game.handleCellClick(3);
    assert(game.currentPlayer === 'O', '세 번째 이동 후 O 차례');
}

// 테스트 8: 이미 차있는 셀에 다시 클릭할 수 없음
console.log('\n테스트 8: 이미 차있는 셀에 다시 클릭할 수 없음');
{
    const game = new TicTacToe();
    game.handleCellClick(0); // X
    const boardBefore = [...game.board];

    game.handleCellClick(0); // 같은 위치 다시 클릭 시도
    assert(game.board[0] === 'X', '셀이 X로 유지되어야 함');
    assert(game.currentPlayer === 'O', '턴이 바뀌지 않아야 함');
}

// 테스트 9: 리셋 기능
console.log('\n테스트 9: 리셋 기능');
{
    const game = new TicTacToe();
    game.handleCellClick(0);
    game.handleCellClick(1);
    game.handleCellClick(2); // X 승리

    assert(game.gameOver === true, '게임이 끝난 상태');
    assert(game.winner === 'X', 'X가 우승');

    game.reset();

    assert(game.board.every(cell => cell === null), '보드가 비워져야 함');
    assert(game.currentPlayer === 'X', '플레이어가 X로 초기화되어야 함');
    assert(game.gameOver === false, '게임이 리셋되어야 함');
    assert(game.winner === null, '승자가 null이어야 함');
    assert(game.winningCells.length === 0, '우승 셀이 비워져야 함');
}

// 테스트 10: 게임 끝난 후 클릭 무시
console.log('\n테스트 10: 게임 끝난 후 클릭 무시');
{
    const game = new TicTacToe();
    game.handleCellClick(0); // X
    game.handleCellClick(3); // O
    game.handleCellClick(1); // X
    game.handleCellClick(4); // O
    game.handleCellClick(2); // X - 승리!

    const boardBefore = [...game.board];
    game.handleCellClick(4); // 게임 끝난 후 클릭 시도

    assert(game.board[4] === 'O', '기존 보드가 변경되지 않음');
    assert(game.gameOver === true, '게임 종료 상태 유지');
}

console.log('\n✅ 모든 테스트 완료!\n');

