class TicTacToe {
    constructor() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;
        this.winningCells = [];

        // DOM이 있는 경우에만 이벤트 리스너 추가 (테스트 환경 지원)
        if (typeof document !== 'undefined') {
            this.cells = document.querySelectorAll('.cell');
            this.turnDisplay = document.getElementById('turn');
            this.winnerDisplay = document.getElementById('winner');
            this.winnerText = document.getElementById('winner-text');
            this.drawDisplay = document.getElementById('draw');
            this.resetBtn = document.getElementById('reset');

            this.initializeEventListeners();
        }
    }

    initializeEventListeners() {
        this.cells.forEach((cell, index) => {
            cell.addEventListener('click', () => this.handleCellClick(index));
        });
        this.resetBtn.addEventListener('click', () => this.reset());
    }

    handleCellClick(index) {
        // 이미 차있거나 게임이 끝났으면 무시
        if (this.board[index] !== null || this.gameOver) {
            return;
        }

        // 셀에 현재 플레이어 표시
        this.board[index] = this.currentPlayer;
        this.cells[index].textContent = this.currentPlayer;
        this.cells[index].classList.add(this.currentPlayer.toLowerCase());
        this.cells[index].disabled = true;

        // 승리 확인
        if (this.checkWin()) {
            this.gameOver = true;
            this.winner = this.currentPlayer;
            this.highlightWinningCells();
            this.updateDisplay();
            return;
        }

        // 무승부 확인
        if (this.checkDraw()) {
            this.gameOver = true;
            this.updateDisplay();
            return;
        }

        // 플레이어 전환
        this.currentPlayer = this.currentPlayer === 'X' ? 'O' : 'X';
        this.updateDisplay();
    }

    checkWin() {
        // 승리 조건 정의
        const winPatterns = [
            // 행
            [0, 1, 2],
            [3, 4, 5],
            [6, 7, 8],
            // 열
            [0, 3, 6],
            [1, 4, 7],
            [2, 5, 8],
            // 대각선
            [0, 4, 8],
            [2, 4, 6]
        ];

        return winPatterns.some(pattern => {
            const [a, b, c] = pattern;
            if (
                this.board[a] === this.currentPlayer &&
                this.board[b] === this.currentPlayer &&
                this.board[c] === this.currentPlayer
            ) {
                this.winningCells = pattern;
                return true;
            }
            return false;
        });
    }

    checkDraw() {
        return this.board.every(cell => cell !== null);
    }

    highlightWinningCells() {
        this.winningCells.forEach(index => {
            this.cells[index].classList.add('winning');
        });
    }

    updateDisplay() {
        if (this.gameOver) {
            if (this.winner) {
                this.turnDisplay.classList.add('hidden');
                this.winnerDisplay.classList.remove('hidden');
                this.drawDisplay.classList.add('hidden');
                this.winnerText.textContent = this.winner;
            } else {
                this.turnDisplay.classList.add('hidden');
                this.winnerDisplay.classList.add('hidden');
                this.drawDisplay.classList.remove('hidden');
            }
            this.resetBtn.textContent = '다시 시작';
        } else {
            this.turnDisplay.classList.remove('hidden');
            this.winnerDisplay.classList.add('hidden');
            this.drawDisplay.classList.add('hidden');
            document.querySelector('#turn strong').textContent = this.currentPlayer;
        }
    }

    reset() {
        // 게임 상태 초기화
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;
        this.winningCells = [];

        // UI 초기화
        this.cells.forEach(cell => {
            cell.textContent = '';
            cell.classList.remove('x', 'o', 'winning');
            cell.disabled = false;
        });

        // 디스플레이 업데이트
        this.updateDisplay();
        this.resetBtn.textContent = '게임 시작';
    }
}

// 페이지 로드 시 게임 시작
document.addEventListener('DOMContentLoaded', () => {
    new TicTacToe();
});

